var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"각하. 합중국 HQ인원들이 위치한 B-7지역에서 다이브 반응이 포착되었습니다.","JPN":"閣下。合衆国HQの人員が位置するB-7地域にて、ダイブ反応を捕捉しました。","ENG":"Ma'am. We've detected a dive signature from Sector B-7 where the States HQ personnel are located.","TWN":"閣下，合眾國HQ人員所在的B-7區域捕捉到躍入反應。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L4_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"추정 상, 나탈리아 님을 비롯한 소수 인원이 작전조를 구하기 위해 투입된 것 같습니다.","JPN":"ナタリア様をはじめとする少数の人員が、作戦組を救出するために向かったと推定されます。","ENG":"Likely a small team with Natalia among them inserted to rescue the operations team.","TWN":"根據推斷，包含那塔利亞在內的少數人員似乎已經投入拯救作戰組。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"구출조를 파견할까요?","JPN":"救出組を派遣しましょうか？","ENG":"Shall we dispatch a rescue team?","TWN":"要派遣救援組嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"…아니. 대균열에 위치한 사도의 목적은 <color=#ffd34c>멸망</color>이 아닌 <color=#ffd34c>시련</color>이야.","JPN":"……いや。大亀裂にいる使徒の目的は<color=#ffd34c>滅亡</color>ではなく<color=#ffd34c>試練</color>だ。","ENG":"...No. The Apostles in the Grand Dimension Crevice aren't here for <color=#ffd34c>annihilation</color>. This is a <color=#ffd34c>trial</color>.","TWN":"…不，位於大峽谷的使徒目的不是<color=#ffd34c>滅亡</color>，而是<color=#ffd34c>試煉</color>。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"클리포트 게임의 상대가 북의 폭군이 아닌 이상, 구태여 움직일 필요는 없지.","JPN":"クリフォトゲームの相手が北の暴君でない限り、わざわざ動く必要はない。","ENG":"Unless their Qliphoth Game opponent is Tyrant of the North, there's no need for us to move.","TWN":"既然逆卡巴拉遊戲的對手不是北方暴君，就沒必要硬是行動。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"기조는 변함없어.","JPN":"方針は変わらない。","ENG":"Our position doesn't change.","TWN":"大局沒有改變。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"북방합의체는…… 현 전황을 유지한다.","JPN":"北方合意体は……現状況を維持する。","ENG":"The Northern Union... maintains the current front.","TWN":"北方和議會……維持現狀。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"휴우. 심층에 진입하니 침식체가 확실히 늘었네요.","JPN":"ふう、深層に入ったからか、目に見えて侵食体が増えましたね。","ENG":"Whew. Deeper we go, the more C.O.s we see.","TWN":"呼，進入深層之後，侵蝕體的確增加了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_CHAINSAW_ATTACK_SMALL"},{"id":"L19_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"대균열 확장의 영향으로 제법 강해진 것도 같으니, 여기서부터는 긴장하는 게 좋겠어요.","JPN":"大亀裂拡張の影響で結構強くなってる気がするし、ここからは気を引き締めていきましょう。","ENG":"And they're tougher from the Grand Dimension Crevice's expansion. Time to stay sharp.","TWN":"受到大峽谷擴張影響，感覺也變得很強大，從這裡開始最好繃緊神經。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"포, 폭실아. 이제 어디로 가면 돼?","JPN":"モ、モコ。今度はどっちに行けばいいの？","ENG":"F-Fluffox. Which way do we go now?","TWN":"福、福實，現在要往哪裡走？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"오, 오른쪽…!","JPN":"み、右……！","ENG":"R-right...!","TWN":"右、右邊…！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE_04"},{"id":"L24_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"또 오른쪽이에요? 아까부터 빙빙 돌기만 하는 것 같은데.","JPN":"また右ですか？　さっきから同じ場所をぐるぐる回ってる気がするけど。","ENG":"Right again? Feels like we're just circling.","TWN":"又是右邊？從剛才開始好像一直在繞來繞去。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_HAIR","text":{"KOREA":"응. 확실히 이상해.","JPN":"うん。確かにおかしい。","ENG":"Yeah. Something's off.","TWN":"嗯，的確很奇怪。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L27_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_HAIR","text":{"KOREA":"풍경도 뭔가 반복되는 기분이고… 대균열 안이라지만 센서도 작동하지 않아.","JPN":"景色もなんだか繰り返されている気がするし……大亀裂の中とはいえ、センサーも作動しない。","ENG":"The scenery's repeating... and being inside the Grand Dimension Crevice has my sensors all dead.","TWN":"總覺得景色也在重複…雖然說是大峽谷內部，但感應器也沒啟動。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_HAIR","text":{"KOREA":"그 아이. 어쩌면 고장 났을지도.","JPN":"その子、もしかしたら壊れてるのかも。","ENG":"Your buddy might be broken.","TWN":"那個孩子說不定故障了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"그, 그럴 일은 없어요. 폭실이는 북방에서도 손꼽히는 최신형이거든요.","JPN":"そ、そんなはずありません。モコは北方でも指折りの最新型なんです。","ENG":"N-no way. Fluffox's a top-tier model, even up in the north.","TWN":"不、不會有那種事，福實在北方也是數一數二的最新型。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"야, 싸가지. 본부로 돌아가는 방향은 어디야?","JPN":"おい。本部に帰る道はどっちなんだ？","ENG":"Hey, brat. Which way back to HQ?","TWN":"喂，沒教養的，回本部的方向是哪裡？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"어라.","JPN":"あれ。","ENG":"Huh?","TWN":"咦。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_DOG_VOICE_04"},{"id":"L35_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"오, 오른쪽. 이라고…?","JPN":"み、右って……？","ENG":"I-it says... right. Again...?","TWN":"右、右邊嗎…？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_HAIR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"고장 난 게 아니라면…….","JPN":"壊れたわけじゃないなら……","ENG":"If it isn't busted...","TWN":"如果不是故障的話……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"답 나왔네.","JPN":"答えは決まってるね。","ENG":"Then we have our answer.","TWN":"答案就很明顯了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_CHAINSAW_START"},{"id":"L41_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"으, 으아아앗…!","JPN":"う、うわああっ……！","ENG":"E-eep...!","TWN":"呃、呃啊啊啊…！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_02"},{"id":"L42_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"두, 둘 다, 난동은 안 돼요…! 침식체들이 몰려올 거라고요…!!","JPN":"ふ、2人とも、暴れちゃダメです……！　侵食体が集まって来ちゃいますよ！","ENG":"H-hey, don't just start smashing...! You'll draw the C.O.s...!!","TWN":"妳、妳們兩個都不能鬧事…！侵蝕體會湧上來…！！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"걔네 부르는 거 맞는데요? 생각해보면, 지금까지 나와야 할 녀석이 나오지 않았잖아요.","JPN":"わざと呼んでるんですけど？　よく考えたら、出てきてもおかしくないやつが出てきてないじゃないですか。","ENG":"That's the point. Think about it. Something that should've shown already hasn't.","TWN":"我的確是在呼喚他們，仔細想想，該出現的傢伙到現在都沒有出現。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_HAIR","text":{"KOREA":"응. 네 길잡이 친구가 고장 난 게 아니라면, 문제는 대균열 쪽에 있다는 소리야.","JPN":"そう。あなたの友だちが壊れたわけじゃないなら、問題は大亀裂にあるってこと。","ENG":"Yeah. If your guide isn't broken, the problem's the Grand Dimension Crevice itself.","TWN":"嗯，意思是如果妳帶路的朋友沒有故障，問題就出在大峽谷那裡。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_HAIR","text":{"KOREA":"그렇다면…….","JPN":"だとしたら……","ENG":"Which means...","TWN":"那麼……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"우와아앗…! 대, 대균열의 벽이…!","JPN":"うわああっ……！　だ、大亀裂の壁が……！","ENG":"Whooooa! Th-the Grand Dimension Crevice's wall...!","TWN":"嗚哇啊啊…！大、大峽谷的牆壁…！"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"…어라? 대균열의 벽이 무, 무너졌네?","JPN":"……あれ？　大亀裂の壁が、こ、壊れた？","ENG":"H-huh? The Grand Dimension Crevice's wall actually... broke?","TWN":"…咦？大峽谷的牆壁倒、倒塌了？"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"대균열 확장이 마왕의 영향이라면 사도들이 비슷한 힘을 다뤄도 이상할 건 없죠.","JPN":"大亀裂の拡張が魔王の影響なら、使徒が似たような力を扱ってもおかしくない。","ENG":"If the expansion is the Demon Lord's doing, it makes sense that the Apostles use similar tricks.","TWN":"如果大峽谷擴張是受魔王影響，那使徒們操控相似的力量也不奇怪。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_CHAINSAW_ATTACK_SMALL"},{"id":"L6_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"지형 자체를 바꾼 게 아닌 단순한 눈속임이라, 이런 식으로 금방 들통나게 되지만.","JPN":"地形そのものを変えたわけじゃなくて単なる目眩ましだから、こうやってすぐバレますけどね。","ENG":"It's just a cheap illusion, not terrain rewrite. So it gets exposed this easily.","TWN":"不是改變地形本身，而是純粹掩人耳目，這種方式很快就會露餡。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"MINISTRA_CORRUPTED_NULL_APOSTLE","text":{"KOREA":"후후…….","JPN":"ふふ……","ENG":"Fufu...","TWN":"呵呵……"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPTED_NULL_APOSTLE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_DAMAGE_DOWN"},{"id":"L9_1","type":"dialog","speaker":"MINISTRA_CORRUPTED_NULL_APOSTLE","text":{"KOREA":"제 풀에 지쳐 쓰러지길 기다렸건만, 벌레들이 복에 겨운 줄 모르고 제 복을 걷어차는구나.","JPN":"疲れて倒れるまで待つつもりだったのに。虫けらは自分が幸福であることも知らずに、自ら不幸の道を選ぶのね。","ENG":"I was content to let you collapse under your own fatigue, yet you worms kick away your blessed rest.","TWN":"本來在等著你們自己氣餒倒下，沒想到這些臭蟲子身在福中不知福，還踢走自己的福氣。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPTED_NULL_APOSTLE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINISTRA_CORRUPTED_NULL_APOSTLE","text":{"KOREA":"이 이상 편안한 안식이 없다는 걸, 왜 몰라주는 걸까?","JPN":"これ以上の安息はないということが、なぜわからないのかしら。","ENG":"Why spurn the sweetest peace you will ever know?","TWN":"為什麼不知道再也沒有比此更安逸的安息呢？"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPTED_NULL_APOSTLE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"에이, 지금 막 경품이 기어 나왔는데 복을 걷어차긴 누가 걷어차?","JPN":"またまた～、ちょうど今景品が出てきたのに、この機を逃す人なんている？","ENG":"Please. The prize just crawled out of the box for us.","TWN":"唉唷，現在贈品都爬出來了，是誰踢走福氣啊？"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L14_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"포장지 뜯고 내용물 확인하기 번거로우니까 알아서 목이나 내밀어, 경품.","JPN":"箱開けて中身確認するのも面倒くさいから、自分から首出しな、景品さん。","ENG":"Unwrap yourself and stick your neck out, prize. I don't like tearing packaging.","TWN":"拆開包裝確認內容物很麻煩，就自己伸出脖子來吧，贈品。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MINISTRA_CORRUPTED_NULL_APOSTLE","text":{"KOREA":"난폭하긴. 그런데 이걸 어쩌지?","JPN":"乱暴ね。でも困ったわ。","ENG":"So rough. But there is a problem.","TWN":"還真野蠻，不過這該怎麼辦？"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPTED_NULL_APOSTLE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINISTRA_CORRUPTED_NULL_APOSTLE","text":{"KOREA":"나보단…… 너희들이 목을 내밀어야 할 것 같은데.","JPN":"首を出すのは……あなたたちがしてくれないと。","ENG":"Looks like you will be the ones offering up your necks.","TWN":"比起我……應該是你們要伸出脖子。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPTED_NULL_APOSTLE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"와, 요즘 그림자는 위트도 있네. 우릴 위해 추가 선물까지 준비한 거야?","JPN":"わあ、最近のシャドウはセンス抜群だね。私たちのためにおまけまで用意してくれたの？","ENG":"Wow, Shadows have wit now? Brought bonus gifts for us, too?","TWN":"哇，最近的暗影也很機智呢，還為我們準備額外的禮物？"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"오른쪽이랑 왼쪽 중에, 어디 보자…….","JPN":"どれどれ、右と左で……","ENG":"Left or right...? Let's see...","TWN":"右邊和左邊之中，讓我看看……"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_HAIR","text":{"KOREA":"난 왼쪽.","JPN":"私は左。","ENG":"I'll take the left one.","TWN":"我選左邊。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L27_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"앗, 통했다. 전 오른쪽이었는데.","JPN":"あっ、気が合うね。私は右がいいと思ってたんです。","ENG":"Oh, nice. I was gonna say right.","TWN":"啊，相通了，我是選右邊。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"좋아요, 선물배분도 끝났겠다-.","JPN":"よし、分配も決まったことだし……","ENG":"Great, the presents are divvied up, so...","TWN":"很好，禮物也分配完了。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"후딱 처리하고 나아가죠.","JPN":"さっさと片付けて進まないとね。","ENG":"Let's take care of them quick and move on.","TWN":"快點處理完繼續吧。"},"stage":{"bg":"BASEMENT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};